    int32_t padW = attrs->GetAttrPointer<int32_t>(8)[0];

    // Compute output dimensions
    int32_t outD = (inD + 2 * padD - kernelD) / strideD + 1;
    int32_t outH = (inH + 2 * padH - kernelH) / strideH + 1;
    int32_t outW = (inW + 2 * padW - kernelW) / strideW + 1;
    uint32_t totalLength = static_cast<uint32_t>(n) * static_cast<uint32_t>(c) * static_cast<uint32_t>(outD) * static_cast<uint32_t>(outH) * static_cast<uint32_t>(outW);

    // Determine tile length
    constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;
    uint32_t tileLen = UB_BUDGET_BYTES / sizeof(float) / 2;  // reserve half for temp
    if (tileLen > 4096) tileLen = 4096;
    if (tileLen > totalLength) tileLen = totalLength;

    // Block dimension: number of tiles to process in parallel
    uint32_t blockDim = 8;
    if (totalLength > 0 && totalLength / tileLen < 8) {
        blockDim = totalLength / tileLen;
        if (blockDim < 1) blockDim = 1;
    }

    context->SetBlockDim(blockDim);

    // Assign fields directly (no setter methods)
    tiling.blockDim = blockDim;
    tiling.totalLength = totalLength;
    tiling.tileLength = tileLen;
    tiling.n = n;
    tiling.c = c;
    tiling.inD = inD;
    tiling.inH = inH;
    tiling.inW = inW;
    tiling.outD = outD;
    tiling.outH = outH;
    tiling.outW = outW;
