    tiling.strideH = strideH;
    tiling.strideW = strideW;
    tiling.padD = padD;
    tiling.padH = padH;
    tiling.padW = padW;
    tiling.invKernelVol = 1.0f / static_cast<float>(kernelD * kernelH * kernelW);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
